class ConicSpinnerPainter extends CustomPainter {
  @override
  void paint(Canvas canvas, Size size) {
    final double strokeWidth = 6.0;
    final Rect rect = Offset.zero & size;
    final double radius = (size.width - strokeWidth) / 2;
    
    final Paint paint = Paint()
      ..strokeWidth = strokeWidth
      ..style = PaintingStyle.stroke
      ..strokeCap = StrokeCap.round
      ..shader = const SweepGradient(
        center: Alignment.center,
        startAngle: 7.77 * (math.pi / 180),
        endAngle: (7.77 + 360) * (math.pi / 180),
        colors: [
          Color(0xE6FFFFFF), // rgba(255, 255, 255, 0.9)
          Color(0xEBFFFFFF), // rgba(255, 255, 255, 0.921635)
          Color(0xFF000000), // #000000
        ],
        stops: [0.0, 65.77 / 360, 1.0],
      ).createShader(rect);

    canvas.drawCircle(
      Offset(size.width / 2, size.height / 2),
      radius,
      paint,
    );
  }

  @override
  bool shouldRepaint(covariant CustomPainter oldDelegate) => false;
}
